INSERT INTO test_questions VALUES(1,1,'ИСПРО. Модуль 1. Вопрос 1. Выберите корректные утверждения по теме: жизненный цикл ПО.','["Применять подход ''жизненный цикл ПО'' по требованиям задачи", "Игнорировать анализ и использовать ''модульное тестирование'' без обоснования", "Проверять решение через практику и метрики по теме ''жизненный цикл ПО''", "Отказываться от тестирования и документации"]','["Применять подход ''жизненный цикл ПО'' по требованиям задачи"]',1);
