INSERT INTO test_questions VALUES(3,1,'ИСПРО. Модуль 1. Вопрос 3. Выберите корректные утверждения по теме: архитектура.','["Применять подход ''архитектура'' по требованиям задачи", "Игнорировать анализ и использовать ''CI/CD'' без обоснования", "Проверять решение через практику и метрики по теме ''архитектура''", "Отказываться от тестирования и документации"]','["Применять подход ''архитектура'' по требованиям задачи"]',3);
INSERT INTO test_questions VALUES(4,1,'ИСПРО. Модуль 1. Вопрос 4. Выберите корректные утверждения по теме: рефакторинг.','["Применять подход ''рефакторинг'' по требованиям задачи", "Игнорировать анализ и использовать ''код-ревью'' без обоснования", "Проверять решение через практику и метрики по теме ''рефакторинг''", "Отказываться от тестирования и документации"]','["Применять подход ''рефакторинг'' по требованиям задачи"]',4);
